+    ASSERT_FALSE(asx_task_is_terminal(ASX_TASK_CREATED));
+    ASSERT_FALSE(asx_task_is_terminal(ASX_TASK_RUNNING));
+    ASSERT_FALSE(asx_task_is_terminal(ASX_TASK_CANCEL_REQUESTED));
